// ─── Helpers ──────────────────────────────────────────────────────────────────
const uid = ()=>Math.random().toString(36).slice(2, 9);
// ─── Audio Beep Utility ───────────────────────────────────────────────────────
function playBeep(type) {
    try {
        const ctx = new (window.AudioContext || window.webkitAudioContext)();
        const o = ctx.createOscillator();
        const g = ctx.createGain();
        o.connect(g);
        g.connect(ctx.destination);
        if (type === "success") {
            // Two-tone ascending beep
            o.frequency.setValueAtTime(880, ctx.currentTime);
            o.frequency.setValueAtTime(1100, ctx.currentTime + 0.12);
            g.gain.setValueAtTime(0.4, ctx.currentTime);
            g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.35);
            o.start(ctx.currentTime);
            o.stop(ctx.currentTime + 0.35);
        } else if (type === "error") {
            // Low descending buzz
            o.frequency.setValueAtTime(300, ctx.currentTime);
            o.frequency.setValueAtTime(150, ctx.currentTime + 0.15);
            g.gain.setValueAtTime(0.5, ctx.currentTime);
            g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.4);
            o.type = "sawtooth";
            o.start(ctx.currentTime);
            o.stop(ctx.currentTime + 0.4);
        } else {
            // Duplicate — single mid tone
            o.frequency.setValueAtTime(600, ctx.currentTime);
            g.gain.setValueAtTime(0.3, ctx.currentTime);
            g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
            o.start(ctx.currentTime);
            o.stop(ctx.currentTime + 0.25);
        }
    } catch  {}
}
// ─── WhatsApp Notify (fire-and-forget) ───────────────────────────────────────
async function notifyWhatsApp(phone, studentName) {
    if (!phone) return;
    try {
        await fetch("/api/whatsapp-notify", {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: JSON.stringify({
                phone,
                studentName,
                time: new Date().toLocaleTimeString("en-US", {
                    hour: "2-digit",
                    minute: "2-digit"
                })
            })
        });
    } catch  {}
}
const today = new Date().toISOString().split("T")[0];
function downloadCSV(filename, rows) {
    const content = rows.map((r)=>r.map((cell)=>`"${String(cell).replace(/"/g, '""')}"`).join(",")).join("\n");
    const blob = new Blob([
        content
    ], {
        type: "text/csv;charset=utf-8;"
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = filename;
    a.click();
    setTimeout(()=>URL.revokeObjectURL(url), 1000);
}
