    function importStudentsCSV(text) {
        const rows = parseCSV(text);
        const ns = rows.map((r)=>{
            if (!r.name || !r.rollno) return null;
            const cid = state.classes.find((c)=>c.name === r.class && c.section === r.section)?.id || state.classes[0]?.id || "";
            return {
                id: uid(),
                name: r.name,
                rollNo: r.rollno,
                classId: cid,
                photo: `https://api.dicebear.com/7.x/avataaars/svg?seed=${r.name}`,
                marks: {},
                password: r.password || "changeme",
                profile: encProfile({
                    dob: r.dob || "",
                    gender: r.gender || "",
                    phone: r.phone || "",
                    address: r.address || "",
                    parentName: r.parent_name || "",
                    parentPhone: r.parent_phone || "",
                    bloodGroup: r.blood_group || "",
                    nic: ""
                })
            };
        }).filter(Boolean);
        if (!ns.length) {
            setCsvMsg("No valid rows. Required columns: name, rollno");
            return;
        }
        const newOnes = ns.filter((n)=>!state.students.find((x)=>x.rollNo === n.rollNo));
        newOnes.forEach((s)=>db.addStudent(s));
        setCsvMsg(`✓ Imported ${newOnes.length} students successfully`);
    }
    function importTeachersCSV(text) {
        const rows = parseCSV(text);
        const nt = rows.map((r)=>{
            if (!r.name || !r.email) return null;
            return {
                id: uid(),
                name: r.name,
                email: r.email,
                subjectIds: [],
                classIds: [],
                password: r.password || "changeme",
                profile: encProfile({
                    dob: r.dob || "",
                    gender: r.gender || "",
                    phone: r.phone || "",
                    address: r.address || "",
                    qualification: r.qualification || "",
                    specialization: r.specialization || "",
                    joinDate: r.join_date || r.joindate || "",
                    nic: r.nic || ""
                })
            };
        }).filter(Boolean);
        if (!nt.length) {
            setCsvMsg("No valid rows. Required columns: name, email");
            return;
        }
        const newOnes = nt.filter((n)=>!state.teachers.find((x)=>x.email === n.email));
        newOnes.forEach((t)=>db.addTeacher(t));
        setCsvMsg(`✓ Imported ${newOnes.length} teachers successfully`);
    }
    function importTimetableCSV(text) {
        const rows = parseCSV(text);
        let count = 0;
        const toSync = [];
        rows.forEach((r)=>{
            const cls = state.classes.find((c)=>c.name === r.class && c.section === r.section);
            const sub = state.subjects.find((s)=>s.code === r.subject_code || s.name.toLowerCase() === r.subject?.toLowerCase());
            const tch = state.teachers.find((t)=>t.email === r.teacher_email || t.name === r.teacher_name);
            const period = parseInt(r.period);
            if (cls && sub && r.day && !isNaN(period)) {
                count++;
                const id = uid();
                toSync.push({
                    id,
                    class_id: cls.id,
                    day: r.day,
                    period,
                    subject_id: sub.id,
                    teacher_id: tch?.id || null
                });
                upd((s)=>({
                        ...s,
                        timetable: {
                            ...s.timetable,
                            [cls.id]: [
                                ...(s.timetable[cls.id] || []).filter((x)=>!(x.day === r.day && x.period === period)),
                                {
                                    day: r.day,
                                    period,
                                    subjectId: sub.id,
                                    teacherId: tch?.id || ""
                                }
                            ]
                        }
                    }));
            }
        });
        toSync.forEach((row)=>{
            try {
                sb.upsert("timetable", row);
            } catch  {}
        });
        setCsvMsg(count ? `✓ Imported ${count} timetable slots` : "No valid rows. Required: class,section,day,period,subject_code");
    }
    function scanQr() {
        const s = state.students.find((s)=>s.rollNo === qrIn.trim());
        if (!s) return;
        upd((st)=>({
                ...st,
                attendance: {
                    ...st.attendance,
                    [today]: {
                        ...st.attendance[today] || {},
                        [s.rollNo]: true
                    }
                }
            }));
        setQrOk(s);
        setQrIn("");
        setTimeout(()=>setQrOk(null), 3000);
    }
